create table dirkspzm32.aps_plan_ergebnis (
    sid                 varchar2(2 char) default '01' not null enable,
    firma_nr            number(2, 0) default 1 not null enable,
    aps_plan_status     varchar2(3 char) not null enable,
    aps_plan_auftrag_nr number(*, 0) not null enable,
    ab_text1            varchar2(255 char),
    ab_text2            varchar2(255 char),
    ab_text3            varchar2(255 char),
    ag_text1            varchar2(255 char),
    ag_text2            varchar2(255 char),
    ag_text3            varchar2(255 char),
    ag_bez1             varchar2(255 char),
    ag_bez2             varchar2(255 char),
    termin_start_gepl   date,
    termin_ende_gepl    date,
    duedate             date,
    earliest_start_date date,
    fixed_properties    number(*, 0),
    info_debug          varchar2(4000 char),
    locked              number(*, 0),
    artikel_id          number,
    planning_type       number,
    priority            number,
    soll_menge          number(*, 3),
    routing_id          varchar2(50 char),
    scheduling_status   number,
    status              number,
    value_production    number,
    transfer_status     varchar2(3 char) default 'N' not null enable,
    fehler_code         number default 0 not null enable,
    fehler_text         varchar2(255 char),
    adr_id              number not null enable,
    leitzahl            number,
    erstell_datum       date default sysdate not null enable,
    bearb_datum         date,
    abnr                varchar2(20 char)
);

alter table dirkspzm32.aps_plan_ergebnis
    add constraint pk_aps_plan_ergebnis
        primary key ( aps_plan_auftrag_nr,
                      aps_plan_status,
                      firma_nr,
                      sid )
            using index enable;


